window.demo = {
  canvas: heroCanvas,
  setTime(t) {
    heroRenderer.setTime(t);
  },
  pause() {
    heroRenderer.pause();
  }
};

// Handle page visibility
document.addEventListener('visibilitychange', () => {
  if (document.hidden) heroRenderer.pause();
  else heroRenderer.resume();
});
